// Terminal/Code block avec syntaxe colorée
const V2Terminal = ({ title = 'Configuration', code, children }) => (
  <div className="mt-6">
    {title && (
      <h3 className="text-lg font-bold text-white flex items-center gap-2 mb-4">
        <Terminal size={20} className="text-purple-500" /> {title}
      </h3>
    )}
    <div className="relative group">
      <div className="absolute -inset-0.5 bg-gradient-to-r from-purple-500/20 to-blue-500/20 rounded-xl blur opacity-75 group-hover:opacity-100 transition duration-1000" />
      <div className="relative bg-black/80 rounded-xl border border-white/10 overflow-hidden shadow-2xl">
        <div className="flex items-center justify-between px-4 py-2 bg-white/5 border-b border-white/5">
          <div className="flex gap-2">
            <div className="w-2.5 h-2.5 rounded-full bg-red-500/20 border border-red-500/40" />
            <div className="w-2.5 h-2.5 rounded-full bg-amber-500/20 border border-amber-500/40" />
            <div className="w-2.5 h-2.5 rounded-full bg-emerald-500/20 border border-emerald-500/40" />
          </div>
          <div className="text-[10px] uppercase tracking-widest text-slate-500 font-bold font-mono">Cisco IOS — Console</div>
        </div>
        <div className="p-6 font-mono text-sm leading-relaxed overflow-x-auto">
          {code ? code.split('\n').map((line, i) => (
            <div key={i} className="flex gap-4">
              <span className="text-slate-700 select-none w-5 text-right shrink-0">{i + 1}</span>
              <span className={
                line.startsWith('!') || line.startsWith('//') ? 'text-slate-600 italic' :
                line.includes('#') && (line.includes('hostname') || line.includes('crypto') || line.includes('ip domain') || line.includes('ip address') || line.includes('ip dhcp') || line.includes('ip default') || line.includes('switchport') || line.includes('vlan') || line.includes('encapsulation') || line.includes('no shutdown') || line.includes('logging') || line.includes('snmp') || line.includes('service')) ? 'text-purple-400' :
                line.includes('enable') || line.includes('configure terminal') || line.includes('exit') || line.includes('end') ? 'text-emerald-400' :
                line.includes('>') || line.includes('#') ? 'text-slate-300' :
                line.startsWith('How') || line.startsWith('↳') ? 'text-cyan-400/70 italic text-xs' :
                'text-slate-400'
              }>{line}</span>
            </div>
          )) : children}
        </div>
      </div>
    </div>
  </div>
);

// Cartes d'information en 2 colonnes (Avantages/Pré-requis, etc.)
const V2InfoCards = ({ cards }) => (
  <div className="grid grid-cols-1 md:grid-cols-2 gap-6 my-8">
    {cards.map((card, i) => {
      const colorMap = {
        emerald: { bg: 'bg-emerald-500/5', border: 'border-emerald-500/20', text: 'text-emerald-400' },
        amber: { bg: 'bg-amber-500/5', border: 'border-amber-500/20', text: 'text-amber-400' },
        purple: { bg: 'bg-purple-500/5', border: 'border-purple-500/20', text: 'text-purple-400' },
        red: { bg: 'bg-red-500/5', border: 'border-red-500/20', text: 'text-red-400' },
        blue: { bg: 'bg-blue-500/5', border: 'border-blue-500/20', text: 'text-blue-400' },
        cyan: { bg: 'bg-cyan-500/5', border: 'border-cyan-500/20', text: 'text-cyan-400' },
      };
      const c = colorMap[card.color] || colorMap.purple;
      const Icon = card.icon || CheckCircle2;
      return (
        <div key={i} className={`p-6 rounded-2xl ${c.bg} border ${c.border}`}>
          <h4 className={`${c.text} font-bold text-sm uppercase tracking-wider mb-3 flex items-center gap-2`}>
            <Icon size={16} /> {card.title}
          </h4>
          <ul className="space-y-2 text-sm text-slate-300">
            {card.items.map((item, j) => <li key={j} className="flex items-start gap-2"><span className="text-slate-500 mt-0.5">•</span> {item}</li>)}
          </ul>
        </div>
      );
    })}
  </div>
);

// Boîte de tip/conseil
const V2Tip = ({ title = 'Best Practice', children, color = 'emerald' }) => {
  const colors = {
    emerald: { bg: 'bg-emerald-500/5', border: 'border-emerald-500/20', iconBg: 'bg-emerald-500/10', icon: 'text-emerald-500', title: 'text-emerald-400', text: 'text-emerald-100/70' },
    amber: { bg: 'bg-amber-500/5', border: 'border-amber-500/20', iconBg: 'bg-amber-500/10', icon: 'text-amber-500', title: 'text-amber-400', text: 'text-amber-100/70' },
    red: { bg: 'bg-red-500/5', border: 'border-red-500/20', iconBg: 'bg-red-500/10', icon: 'text-red-500', title: 'text-red-400', text: 'text-red-100/70' },
    purple: { bg: 'bg-purple-500/5', border: 'border-purple-500/20', iconBg: 'bg-purple-500/10', icon: 'text-purple-500', title: 'text-purple-400', text: 'text-purple-100/70' },
  };
  const c = colors[color] || colors.emerald;
  return (
    <div className={`${c.bg} border ${c.border} rounded-xl p-6 flex gap-4 mt-8`}>
      <div className={`p-2 h-fit ${c.iconBg} rounded-lg ${c.icon}`}><Lightbulb size={20} /></div>
      <div>
        <h4 className={`${c.title} font-bold mb-1`}>{title}</h4>
        <div className={`${c.text} text-sm leading-relaxed`}>{children}</div>
      </div>
    </div>
  );
};

