const MemorySimulator = () => {
  const [power, setPower] = useState(true);
  const [ramData, setRamData] = useState("Votre Travail en Cours");
  const [nvramData, setNvramData] = useState("Votre Sauvegarde");
  const [unsavedChanges, setUnsavedChanges] = useState(false);

  useEffect(() => {
    if (!power) {
      setRamData(""); 
      setUnsavedChanges(false);
    } else {
      setRamData(nvramData); 
    }
  }, [power]);

  const handleSave = () => {
    if (power) {
      setNvramData(ramData);
      setUnsavedChanges(false);
    }
  };

  const handleModify = () => {
    if (power) {
      setUnsavedChanges(true);
      setRamData("Travail en cours (NON SAUVÉ)");
    }
  }

  return (
    <div className="bg-[#0e0920] p-6 rounded-xl border border-white/[0.15] shadow-xl">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-8 gap-4">
        <div>
          <h4 className="font-bold text-white flex items-center gap-2 text-lg"><Save className="w-5 h-5 text-purple-500" /> Labo : Pourquoi sauvegarder ?</h4>
          <p className="text-sm text-slate-400 mt-1">Simulez une coupure de courant pour comprendre.</p>
        </div>
        <button 
          onClick={() => setPower(!power)}
          className={`px-6 py-2 rounded-full font-bold flex items-center gap-2 transition-all shadow-lg ${power ? 'bg-emerald-600 text-white shadow-emerald-500/30 hover:bg-emerald-500' : 'bg-red-600 text-white shadow-red-500/30 hover:bg-red-500'}`}
        >
          <Power className="w-4 h-4" /> {power ? "COURANT ON" : "COURANT OFF"}
        </button>
      </div>

      <div className="grid grid-cols-2 gap-8 relative mb-8">
        <div className={`p-6 rounded-xl border-2 transition-all z-10 flex flex-col items-center gap-3 text-center ${power ? 'border-purple-500 bg-purple-900/10' : 'border-white/10 bg-[#0a051a] opacity-50 grayscale'}`}>
          <div className="text-sm font-bold text-purple-400 uppercase tracking-widest">RAM (Le Cerveau)</div>
          <Cpu size={32} className="text-purple-500"/>
          <p className="text-xs text-slate-400">Si je m'éteins, j'oublie tout instantanément.</p>
          <div className={`w-full py-2 rounded font-bold ${power ? 'text-white bg-purple-600/20' : 'text-transparent bg-[#0e0920]'}`}>
            {power ? ramData : "VIDE"}
          </div>
        </div>
        
        <div className="p-6 rounded-xl border-2 border-emerald-500 bg-emerald-900/10 z-10 flex flex-col items-center gap-3 text-center">
          <div className="text-sm font-bold text-emerald-400 uppercase tracking-widest">NVRAM (Le Disque Dur)</div>
          <HardDrive size={32} className="text-emerald-500"/>
          <p className="text-xs text-slate-400">Je garde les infos même sans électricité.</p>
          <div className="w-full py-2 rounded font-bold text-white bg-emerald-600/20">
            {nvramData}
          </div>
        </div>
      </div>

      <div className="flex flex-col sm:flex-row gap-4 pt-6 border-t border-white/10">
        <button onClick={handleModify} disabled={!power} className="flex-1 bg-[#1a1035] hover:bg-[#251845] border border-white/20 text-white py-4 rounded-lg text-sm transition-all">
          1. Travailler (Configurer)
        </button>
        <button onClick={handleSave} disabled={!power} className="flex-1 bg-purple-600 hover:bg-purple-500 text-white py-4 rounded-lg text-sm font-bold shadow-lg shadow-purple-900/20 transition-all">
          2. Sauvegarder (copy run start)
        </button>
      </div>
      
      {!power && unsavedChanges && (
        <div className="mt-6 p-4 bg-red-500/10 border border-red-500/30 rounded-lg text-red-200 text-sm flex items-start gap-3 animate-pulse">
          <AlertTriangle className="w-6 h-6 flex-shrink-0 text-red-500" /> 
          <div>
            <span className="font-bold block text-red-400 text-lg mb-1">CATASTROPHE !</span>
            Vous avez coupé le courant avant de sauvegarder. Tout le travail fait en RAM est perdu à jamais.
          </div>
        </div>
      )}
    </div>
  );
};

// --- FLASHCARDS ---

const FlashCards = ({ cards, mode = 'question_to_answer' }) => {
  const [current, setCurrent] = useState(0);
  const [flipped, setFlipped] = useState(false);

  const nextCard = () => {
    setFlipped(false);
    setTimeout(() => setCurrent((c) => (c + 1) % cards.length), 250);
  };

  const isCommandFirst = mode === 'command_to_definition';

  return (
    <div className="w-full max-w-2xl mx-auto my-8">
      <div
        onClick={() => setFlipped(!flipped)}
        className="relative h-64 w-full cursor-pointer group"
        style={{ perspective: '1000px' }}
      >
        <div
          className="relative w-full h-full"
          style={{
            transformStyle: 'preserve-3d',
            transition: 'transform 0.7s',
            transform: flipped ? 'rotateY(180deg)' : 'rotateY(0deg)',
          }}
        >
          {/* FRONT */}
          <div
            className="absolute inset-0 bg-[#1a1035] border-2 border-white/[0.15] rounded-2xl flex flex-col items-center justify-center p-8 text-center shadow-2xl group-hover:border-purple-500/50 transition-colors"
            style={{ backfaceVisibility: 'hidden' }}
          >
            {isCommandFirst ? (
              <>
                <Terminal className="w-10 h-10 text-emerald-500 mb-4" />
                <span className="text-xs text-emerald-400 font-bold uppercase tracking-wider mb-2">Commande Cisco</span>
                <code className="text-3xl font-mono text-white bg-black/40 px-6 py-4 rounded-xl shadow-inner border border-white/10 break-all w-full">
                  {cards[current].q}
                </code>
              </>
            ) : (
              <>
                <HelpCircle className="w-10 h-10 text-purple-500 mb-4" />
                <span className="text-xs text-purple-400 font-bold uppercase tracking-wider mb-2">Question / Objectif</span>
                <h3 className="text-2xl font-bold text-white leading-tight">
                  "{cards[current].q}"
                </h3>
              </>
            )}
            <p className="text-slate-500 text-xs mt-auto flex items-center gap-2 opacity-60">
              <RotateCcw size={12}/> Cliquer pour voir la {isCommandFirst ? 'définition' : 'commande'}
            </p>
          </div>

          {/* BACK */}
          <div
            className="absolute inset-0 bg-gradient-to-br from-purple-900 to-slate-900 rounded-2xl flex flex-col items-center justify-center p-6 text-center shadow-2xl border-2 border-purple-400/50"
            style={{ backfaceVisibility: 'hidden', transform: 'rotateY(180deg)' }}
          >
            {isCommandFirst ? (
              <>
                <span className="text-xs text-purple-200 font-bold uppercase tracking-wider mb-2">
                  Définition
                </span>
                <h3 className="text-xl font-bold text-white leading-tight mb-2">
                  "{cards[current].a}"
                </h3>
                <p className="text-[11px] text-slate-400 mt-4">
                  Cliquer à nouveau pour revoir la commande.
                </p>
              </>
            ) : (
              <>
                <span className="text-xs text-purple-200 font-bold uppercase tracking-wider mb-2">
                  Commande Cisco
                </span>
                <code className="text-2xl font-mono text-emerald-400 bg-black/40 px-6 py-4 rounded-xl shadow-inner border border-white/10 break-all w-full mb-4">
                  {cards[current].a}
                </code>
                <div className="mt-auto pt-4 border-t border-purple-400/30 w-full opacity-80">
                  <span className="text-[10px] uppercase text-purple-300 font-bold block mb-1">
                    Rappel Objectif
                  </span>
                  <p className="text-purple-200 text-xs italic">"{cards[current].q}"</p>
                </div>
              </>
            )}
          </div>
        </div>
      </div>
      
      <div className="flex justify-between items-center mt-6 bg-[#0e0920] p-4 rounded-xl border border-white/10">
        <span className="text-slate-400 font-mono">Carte {current + 1} / {cards.length}</span>
        <button onClick={nextCard} className="px-6 py-3 bg-[#1a1035] hover:bg-[#251845] text-white rounded-lg flex items-center gap-2 transition-all font-bold border border-white/[0.15] hover:border-purple-500">
          Suivant <ChevronRight size={18} />
        </button>
      </div>
    </div>
  );
};

