              { title: "En pratique", color: "emerald", icon: CheckCircle2, items: ["En lab : n'importe quel nom (lab.local)", "En production : vrai domaine de l'entreprise", "Exemple : novatech.local, cisco.com", "Se configure en mode config globale"] }
