// --- THEORY PLAYER ---

const TheoryPlayer = ({ slides, lab, sessionId }) => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const [direction, setDirection] = useState(0);

  const slide = slides[currentSlide];

  const next = () => {
    if (currentSlide < slides.length - 1) {
      setDirection(1);
      setCurrentSlide(currentSlide + 1);
    }
  };
  const prev = () => {
    if (currentSlide > 0) {
      setDirection(-1);
      setCurrentSlide(currentSlide - 1);
    }
  };

  const slideVariants = {
    enter: (dir) => ({ x: dir > 0 ? 60 : -60, opacity: 0 }),
    center: { x: 0, opacity: 1 },
    exit: (dir) => ({ x: dir > 0 ? -60 : 60, opacity: 0 }),
  };

  const renderSlide = (s) => {
    switch (s.type) {
      case 'mode_explorer':
        return <ModeExplorer />;
      case 'memory_sim':
        return <MemorySimulator />;
      case 'flashcards':
        return <FlashCards cards={s.cards} mode={s.mode} />;
      case 'lab_correction':
        if (lab && lab.solutionContent) return lab.solutionContent;
        return <LabCorrection scenario={lab || s.scenario} />;
      case 'ssh_configurator':
        return <SSHConfigurator />;
      case 'interactive_quiz':
        return <InteractiveQuiz questions={s.questions} />;
      case 'command_builder':
        return <CommandBuilder steps={s.steps} title={s.commandBuilderTitle || s.title} />;
      case 'privilege_explorer':
        return <PrivilegeExplorer />;
      case 'network_diagram':
        return <NetworkDiagram mode={s.mode || 'ssh'} />;
      case 'data_flow':
        return <DataFlowAnimation />;
      case 'dora_flow':
        return <DoraFlowAnimation />;
      case 'config_comparison':
        return <ConfigComparison before={s.before} after={s.after} title={s.title} />;
      case 'ssh_flow':
        return <SSHConnectionFlow />;
      case 'vlan_diagram':
        return <VLANDiagram />;
      case 'trunk_diagram':
        return <TrunkDiagram />;
      case 'deep_dive':
        return (
          <div className="bg-white/[0.03] backdrop-blur-xl p-8 rounded-2xl border border-white/10 shadow-xl">
            <h3 className="text-xl font-bold text-white mb-6">{s.title}</h3>
            <DeepDiveSection items={s.items} />
          </div>
        );
      case 'intro': {
        const lines = (s.content || '').split('\n').filter(l => l.trim());
        const objectiveIdx = lines.findIndex(l => l.includes('la fin de cette'));
        const descLines = objectiveIdx > 0 ? lines.slice(0, objectiveIdx) : lines;
        const objectiveLines = objectiveIdx > 0 ? lines.slice(objectiveIdx + 1) : [];
        return (
          <div className="relative overflow-hidden bg-white/[0.03] backdrop-blur-xl rounded-2xl border border-white/10 shadow-xl">
            <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-purple-500 via-blue-500 to-purple-500" />
            <div className="absolute top-[-30%] right-[-10%] w-[50%] h-[50%] bg-purple-600/5 blur-[100px] rounded-full pointer-events-none" />
            <div className="p-8 md:p-12">
              <div className="mb-8 space-y-4">
                {descLines.map((line, i) => (
                  <p key={i} className={`leading-relaxed ${i === 0 ? 'text-lg text-slate-100 font-medium' : 'text-slate-300'}`}>{line}</p>
                ))}
              </div>
              {objectiveLines.length > 0 && (
                <div className="bg-white/[0.03] rounded-xl border border-white/10 p-6">
                  <h4 className="text-sm font-bold uppercase tracking-widest text-purple-400 mb-5 flex items-center gap-2">
                    <Target size={16} /> Objectifs de la session
                  </h4>
                  <div className="grid gap-3">
                    {objectiveLines.map((line, i) => {
                      const text = line.replace(/^[^\s]+\s/, '');
                      return (
                        <div key={i} className="flex items-start gap-3 group">
                          <div className="mt-0.5 w-6 h-6 rounded-lg bg-gradient-to-br from-purple-500/20 to-blue-500/20 border border-purple-500/30 flex items-center justify-center shrink-0">
                            <CheckCircle2 size={14} className="text-purple-400" />
                          </div>
                          <span className="text-slate-200 text-sm leading-relaxed">{text}</span>
                        </div>
                      );
                    })}
                  </div>
                </div>
              )}
            </div>
          </div>
        );
      }
      case 'rich_text':
        return (
          <div className="bg-white/[0.03] backdrop-blur-xl p-8 md:p-12 rounded-2xl border border-white/10 shadow-xl bg-gradient-to-b from-white/[0.04] to-transparent">
            {s.content}
          </div>
        );
      default:
        return (
          <div className="bg-white/[0.03] backdrop-blur-xl p-8 md:p-12 rounded-2xl border border-white/10 shadow-xl min-h-[260px] flex flex-col justify-center bg-gradient-to-b from-white/[0.04] to-transparent">
            <p className="text-slate-200 whitespace-pre-line leading-relaxed">{s.content}</p>
          </div>
        );
    }
  };

  return (
    <div className="max-w-5xl mx-auto pb-12">
      {/* Slide header */}
      <div className="flex justify-between items-center mb-6 px-1">
        <h2 className="text-xl md:text-2xl font-bold text-white flex items-center gap-3">
          <span className="bg-gradient-to-br from-purple-600 to-blue-600 w-9 h-9 rounded-lg flex items-center justify-center text-sm shadow-lg shadow-purple-900/50">
            {currentSlide + 1}
          </span>
          <span className="text-purple-100">{slide.title}</span>
        </h2>
        <span className="text-xs text-slate-500 font-mono bg-white/5 backdrop-blur px-3 py-1 rounded-full border border-white/10">
          {currentSlide + 1} / {slides.length}
        </span>
      </div>

      {/* Animated slide content */}
      <div className="mb-6 min-h-[300px]">
        <AnimatePresence mode="wait" custom={direction}>
          <motion.div
            key={currentSlide}
            custom={direction}
            variants={slideVariants}
            initial="enter"
            animate="center"
            exit="exit"
            transition={{ duration: 0.3, ease: "easeInOut" }}
          >
            {renderSlide(slide)}
          </motion.div>
        </AnimatePresence>
      </div>

      {/* Bottom navigation - Vibe 2 style */}
      <div className="flex justify-between items-center bg-[#0e0920]/80 backdrop-blur-xl p-4 rounded-xl border border-white/10 sticky bottom-4">
        <button
          onClick={prev}
          disabled={currentSlide === 0}
          className="flex items-center gap-2 px-5 py-2.5 rounded-xl bg-white/5 border border-white/10 text-slate-300 hover:bg-white/10 disabled:opacity-30 transition-all text-sm font-medium group"
        >
          <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" /> Précédent
        </button>

        <div className="hidden md:flex gap-2">
          {slides.map((_, idx) => (
            <div key={idx} className={`h-1.5 rounded-full transition-all duration-500 ${idx === currentSlide ? 'w-8 bg-purple-500 shadow-[0_0_8px_rgba(168,85,247,0.6)]' : 'w-1.5 bg-white/10'}`} />
          ))}
        </div>

        <button
          onClick={next}
          disabled={currentSlide === slides.length - 1}
          className="flex items-center gap-2 px-6 py-2.5 rounded-xl bg-gradient-to-r from-purple-600 to-blue-600 text-white text-sm font-bold disabled:opacity-30 transition-all shadow-lg shadow-purple-500/20 hover:scale-[1.02] active:scale-[0.98] group"
        >
          {currentSlide === slides.length - 1 ? 'Terminer' : 'Suivant'} <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform" />
        </button>
      </div>
    </div>
  );
};

