  const [activeSessionId, setActiveSessionId] = useState(1);
  const [activeTab, setActiveTab] = useState('theory');
  const [completedSessions, setCompletedSessions] = useState([]);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [quizScore, setQuizScore] = useState(null);
  const [expandedWeek, setExpandedWeek] = useState(1);
  const [expandedLabWeek, setExpandedLabWeek] = useState(1);
  // Système de statistiques (sync Supabase)
  const { stats, addTime, addCommand, addQuizAttempt, addLabAttempt, resetStats } = useStats(user?.id);

  // Charger completedSessions depuis Supabase
  useEffect(() => {
    if (!user?.id) return;
    supabase
      .from('student_progress')
      .select('completed_sessions')
      .eq('user_id', user.id)
      .single()
      .then(({ data }) => {
        if (data?.completed_sessions?.length > 0) setCompletedSessions(data.completed_sessions);
      });
  }, [user?.id]);

  // Sauver completedSessions vers Supabase
  useEffect(() => {
    if (!user?.id || completedSessions.length === 0) return;
    supabase
      .from('student_progress')
      .update({ completed_sessions: completedSessions })
      .eq('user_id', user.id);
  }, [completedSessions, user?.id]);
  
  // Tracking du temps passé
  const [sessionStartTime, setSessionStartTime] = useState(Date.now());
  const [timeTracker, setTimeTracker] = useState(null);

  useEffect(() => {
    // Démarrer le tracker de temps
    const interval = setInterval(() => {
      const elapsed = Math.floor((Date.now() - sessionStartTime) / 1000);
      if (elapsed > 0 && elapsed % 30 === 0) { // Sauvegarder toutes les 30 secondes
        addTime(30, activeSessionId);
        setSessionStartTime(Date.now());
      }
    }, 30000);

    return () => clearInterval(interval);
  }, [activeSessionId, sessionStartTime]);

  useEffect(() => {
    // Réinitialiser le timer quand on change de session
    setSessionStartTime(Date.now());
  }, [activeSessionId]);

  const activeSession = sessions.find(s => s.id === activeSessionId);
